"""This module launches a GUI where a user can select which type of platform data to record."""
import argparse
import textwrap
import os
import subprocess
try:
    from Tkinter import Tk, Button, IntVar, Checkbutton, Label
except ImportError:
    from tkinter import Tk, Button, IntVar, Checkbutton, Label
from audio_recorder import AudioRecorder
from video_recorder import VideoRecorder
from websocket_recorder import WebsocketRecorder
from photo_recorder import PhotoRecorder
from time_recorder import TimeRecorder


class Recorder(object):
    """Recorder Class"""

    def __init__(self, controller):
        self.controller = controller
        self.checkbox = IntVar()

    def create_checkbox(self, root):
        """Create UI checkbox"""
        check = Checkbutton(root, text=self.controller.name, variable=self.checkbox)
        check.pack()

class MainRecorder(object):
    """MainRecorder Class"""

    def __init__(self, robot, output_dir):
        self.__robot = robot
        self.__output_dir = output_dir
        self.__recorders = []
        self.__ui_queue = []
        self.__root = Tk()
        self.__has_started = False

        # Setup recorders 
        # For websocket recoder last field is how long the write-out thread should sleep
        # 0.1 is 10hz
        # 0.05 is 20hz
        # 0.025 is 40hz
        # 0.0166 is 60hz
        # 0.0100 is 100hz
        # 0.0066 is 150Hz
        # 0.001 is 1000Hz
        self.__video_mp4 = Recorder(VideoRecorder(
            'video_mp4',
            self.__robot,
            self.__output_dir, self.__root, self.__ui_queue, True))
        self.__audio_wav = Recorder(AudioRecorder(
            'audio_wav',
            self.__robot,
            self.__output_dir, self.__root, self.__ui_queue))
        self.__photo_jpg = Recorder(PhotoRecorder(
            'photo_jpg',
            self.__robot,
            self.__output_dir, self.__root, self.__ui_queue))
        self.__visual_awareness = Recorder(WebsocketRecorder(
            'visual_awareness',
            'ws://' + str(self.__robot) + ':8484/lps/visual_awareness', # Emits at 10hz
            self.__output_dir, self.__root, self.__ui_queue, 0.05)) # Thread at 20hz
        self.__audible_awareness = Recorder(WebsocketRecorder(
            'audible_awareness',
            'ws://' + str(self.__robot) + ':8484/lps/audible_awareness', # Emits at 10hz
            self.__output_dir, self.__root, self.__ui_queue, 0.05)) # Thread at 20hz
        self.__input_energy = Recorder(WebsocketRecorder(
            'input_energy',
            'ws://' + str(self.__robot) + ':8383/input_energy', # Emits at 20hz
            self.__output_dir, self.__root, self.__ui_queue, 0.025)) # Thread at 40hz
        self.__head_touch = Recorder(WebsocketRecorder(
            'head_touch',
            'ws://' + str(self.__robot) + ':8282/touch', # Emits at 1hz but also aperiodic
            self.__output_dir, self.__root, self.__ui_queue, 0.1)) # Thread at 10hz
        self.__jetstream_vad = Recorder(WebsocketRecorder(
            'jetstream_vad',
            'ws://' + str(self.__robot) + ':8090/vad', # Emits at 20hz
            self.__output_dir, self.__root, self.__ui_queue, 0.025)) # Thread at 40hz
        self.__jetstream_events= Recorder(WebsocketRecorder(
            'jetstream_events',
            'ws://' + str(self.__robot) + ':8090/events', # Emits aperiodic status events as fast as 2ms apart
            self.__output_dir, self.__root, self.__ui_queue, 0.1)) # Thread at 10hz
        self.__time_references = Recorder(TimeRecorder(
            'time_references',
            self.__robot,
            self.__output_dir, self.__root, self.__ui_queue))

        # Add to recorders
        self.__recorders.append(self.__video_mp4)
        self.__recorders.append(self.__audio_wav)
        self.__recorders.append(self.__photo_jpg)
        self.__recorders.append(self.__visual_awareness)
        self.__recorders.append(self.__audible_awareness)
        self.__recorders.append(self.__input_energy)
        self.__recorders.append(self.__head_touch)
        self.__recorders.append(self.__jetstream_vad)
        self.__recorders.append(self.__jetstream_events)
        self.__recorders.append(self.__time_references)

        # Create UI
        self.create_ui()

    def start(self):
        """Start GUI"""
        self.__has_started = True
        print('Starting UI main loop')
        self.__root.after(100, self.update_main_ui)
        self.__root.mainloop()

    def start_recordings(self):
        """Create the recorders that were selected in the GUI."""
        # Start all selected recorders
        for rec in self.__recorders:
            if rec.checkbox.get():
                rec.controller.start()

    def stop_recordings(self):
        """Stop all selected recorders"""
        for rec in self.__recorders:
            if rec.checkbox.get():
                rec.controller.stop()

    def exit_program(self):
        """Exit all selected recorders and UI program"""
        for rec in self.__recorders:
            if rec.checkbox.get():
                rec.controller.exit()
        # Exit UI
        self.__root.quit()

    def create_ui(self):
        """Create UI Elements"""
        self.__root.title("Data Collector")
        self.__root.geometry('600x700')
        # Make top most window (toggle on off)
        self.__root.attributes("-topmost", True)
        self.__root.attributes("-topmost", False)
        Label(self.__root, text="").pack()
        self.__label = Label(self.__root, fg="dark blue")
        self.__label.config(text=self.__robot)
        self.__label.pack()

        # Checkboxes
        self.__video_mp4.create_checkbox(self.__root)
        self.__audio_wav.create_checkbox(self.__root)
        self.__photo_jpg.create_checkbox(self.__root)
        self.__visual_awareness.create_checkbox(self.__root)
        self.__audible_awareness.create_checkbox(self.__root)
        self.__input_energy.create_checkbox(self.__root)
        self.__head_touch.create_checkbox(self.__root)
        self.__jetstream_vad.create_checkbox(self.__root)
        self.__jetstream_events.create_checkbox(self.__root)
        self.__time_references.create_checkbox(self.__root)

        # Start Button
        Button(self.__root, text="START", fg="black",
               width=10, command=self.start_recordings).pack()
        # Stop Button
        Button(self.__root, text="STOP", fg="black",
               width=10, command=self.stop_recordings).pack()
        # Exit Button
        Button(self.__root, text="EXIT", fg="black",
               width=10, command=self.exit_program).pack()

    def update_main_ui(self):
        """Update the labels in UI; variable ui_queue is populated by all recorders"""
        while self.__ui_queue:
            element = self.__ui_queue.pop()
            label = element['label']
            text = element['text']
            color = element['color']
            label.config(text=text, fg=color)
            label.pack()
        self.__root.after(100, self.update_main_ui)

def main():
    """Main"""
    # Get desktop path
    home_path = os.path.expanduser('~')
    desktop_path = os.path.join(home_path, 'Desktop')
    jibo_path = os.path.join(home_path, '.jibo/cli.json')
    # Get robot name if jibo cli exists
    robot_addr = '172.24.84.101'
    if os.path.exists(jibo_path):
        try:
            jibo_list = subprocess.Popen(('jibo', 'robot-list'), stdout=subprocess.PIPE)
            output = subprocess.check_output(('grep', '*'), stdin=jibo_list.stdout)
            robot_addr = str(output.split()[2])
            if robot_addr[0] == 'b':
                robot_addr = robot_addr.split("'")[1]
        except FileNotFoundError:
            print('FileNotFoundError: \'jibo\' is not a command; Using default robot address')
    # Get program arguments
    parser = argparse.ArgumentParser(
        prog='main_recorder',
        formatter_class=argparse.RawDescriptionHelpFormatter,
        description=textwrap.dedent('''\
            This program records data from various Jibo services (lps, audio, body, etc).
            A GUI is launched; Select which services to record; Click the start/stop buttons.

            Example:
                python main_recorder.py -r floral-julius-tomato-foil.local -o output/
        '''))
    parser.add_argument('-r',
                        dest='robot',
                        default=robot_addr,
                        help='robot name (default: default robot from \
                        jibo robot-list or 172.24.84.101)',
                        action='store',
                        required=False)
    parser.add_argument('-o',
                        dest='directory',
                        default=desktop_path + '/recordings',
                        help='output directory (default: ~/Desktop/recordings)',
                        action='store',
                        required=False)
    args = parser.parse_args()

    # Create main recorder and start
    main_recorder = MainRecorder(args.robot, os.path.abspath(args.directory))
    main_recorder.start()

if __name__ == '__main__':
    main()
